import React from 'react';
import { View, Text, StyleSheet, SafeAreaView, TouchableOpacity } from 'react-native';
import { useAuth } from '../utils/AuthContext';
import Button from '../components/Button';
import { typography } from '../styles/typography';
import { useNavigation } from '@react-navigation/native';
import { Ionicons } from '@expo/vector-icons';
import { StackNavigationProp } from '@react-navigation/stack';
import { RootStackParamList } from '../navigation/AppNavigator';

const AccountScreen: React.FC = () => {
  const { user, logout, isLoading } = useAuth();
  const navigation = useNavigation<StackNavigationProp<RootStackParamList>>();

  const handleLogout = async () => {
    await logout();
    navigation.reset({ index: 0, routes: [{ name: 'Home' }] });
  };

  return (
    <SafeAreaView style={styles.safeArea}>
      <View style={styles.container}>
        <Text style={typography.heading}>Account</Text>
        <View style={styles.infoBox}>
          <Text style={typography.body}>Email: {user?.email}</Text>
          <Text style={typography.body}>Name: {user?.name}</Text>
        </View>
        <Button onPress={handleLogout} disabled={isLoading}>
          Log Out
        </Button>
      </View>
      <View style={styles.tabBar}>
        <TouchableOpacity style={styles.tabIcon} onPress={() => navigation.navigate('Home')}>
          <Ionicons name="partly-sunny-outline" size={28} color="#757575" />
        </TouchableOpacity>
        <TouchableOpacity style={styles.tabIcon}>
          <Ionicons name="shirt-outline" size={28} color="#757575" />
        </TouchableOpacity>
        <TouchableOpacity style={styles.tabIcon}>
          <Ionicons name="globe-outline" size={28} color="#757575" />
        </TouchableOpacity>
        <TouchableOpacity style={styles.tabIcon}>
          <Ionicons name="person-outline" size={28} color="#000" />
        </TouchableOpacity>
      </View>
    </SafeAreaView>
  );
};

const styles = StyleSheet.create({
  safeArea: {
    flex: 1,
    backgroundColor: '#fff'
  },
  container: {
    flex: 1,
    backgroundColor: '#fff',
    padding: 32,
    justifyContent: 'center',
    alignItems: 'center',
  },
  infoBox: {
    marginVertical: 32,
    width: '100%',
    backgroundColor: '#F5F5F5',
    borderRadius: 12,
    padding: 24,
  },
  tabBar: {
    flexDirection: 'row',
    justifyContent: 'space-around',
    alignItems: 'center',
    height: 60,
    backgroundColor: '#fff'
  },
  tabIcon: {
    flex: 1,
    alignItems: 'center',
    justifyContent: 'center'
  },
});

export default AccountScreen;
